noncompliant:
class Outer
{
    public static int A;

    public class Inner
    {
        public int A; // Noncompliant: shadows outer static member

        public int MyProp
        {
            get => A; // Confusing: which A?
        }
    }
}

compliant:
class Outer
{
    public static int OuterValue;

    public class Inner
    {
        public int InnerValue; // OK: distinct name

        public int MyProp
        {
            get => InnerValue; // Clear
        }
    }
}
